function lightCandle(){document.querySelector(".scene").classList.add("lit")}const btn=document.getElementById("lightCandleBtn"),candle=document.getElementById("candleContainer");btn&&candle&&btn.addEventListener("click",()=>{candle.classList.add("is-visible");const e=document.querySelector(".memory-scene");btn.addEventListener("click",()=>{candle.classList.add("is-visible"),e.classList.add("is-lit")}),btn.style.opacity="0.5",candle.scrollIntoView({behavior:"smooth",block:"center"})});